// Parse payload
var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { node.warn('Bad JSON: ' + msg.payload); return null; }
}

var rssi = d.rssi_dbm;
var ts   = d.ts;

var lastRssi = context.get('lastRssi');  // undefined on first message
var lastTs   = context.get('lastTs') || '';

// Update stored state
context.set('lastRssi', rssi);
context.set('lastTs', ts);

// First message ever — initialise state, no event
if (lastRssi === undefined) {
    return null;
}

var logMsg = null;

if (lastRssi !== 0 && rssi === 0) {
    // Transition home → field: hike started
    // ts is the timestamp of the first field reading = actual hike start time
    logMsg = JSON.stringify({
        component: 'hiking-monitor',
        category:  'System',
        message:   'Hike started at ' + ts
    });
} else if (lastRssi === 0 && rssi !== 0) {
    // Transition field → home: hike ended
    // lastTs is the timestamp of the last field reading = actual hike end time
    logMsg = JSON.stringify({
        component: 'hiking-monitor',
        category:  'System',
        message:   'Hike ended at ' + lastTs
    });
}

if (logMsg) {
    msg.payload = logMsg;
    msg.topic   = 'jctsh/components/hiking-monitor/log';
    return msg;
}

return null;
